// Extract the _embedded.assets array from HAL JSON response
const response = msg.payload || {};
const assets = response._embedded?.assets || response._embedded?.asset || response.content || [];

const mapping = {};
const namesList = [];

// Build mapping of asset name to assetId
// Note: API returns 'assetId' (not 'id') as the unique identifier
assets.forEach(asset => {
    const id = asset.assetId;
    if (asset.name && id) {
        mapping[asset.name] = id;
        namesList.push({
            name: asset.name,
            assetId: id,
            typeId: asset.typeId,
            parentId: asset.parentId
        });
    }
});

msg.payload = {
    assetMap: mapping,
    assetsList: namesList,
    totalCount: namesList.length
};

return msg;

// Store the asset mapping in flow variable for use in other parts
const assetMap = msg.payload.assetMap || {};
const assetsList = msg.payload.assetsList || [];

flow.set('assetNameToIdMap', assetMap);
flow.set('assetsList', assetsList);

msg.payload = {
    message: 'Asset mapping stored in flow variables',
    totalAssets: Object.keys(assetMap).length,
    assetNames: Object.keys(assetMap),
    mapping: assetMap
};

return msg;
